public class Solution {
    public static long solve(long n, long[][] edges) {
        int numNodes = (int) n;
        List<List<long[]>> graph = new ArrayList<>();
        List<List<long[]>> reversedEdges = new ArrayList<>();

        for (int i = 0; i < numNodes; i++) {
            graph.add(new ArrayList<>());
            reversedEdges.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];
            graph.get(u).add(new long[]{v, w});
            reversedEdges.get(v).add(new long[]{u, w});
        }

        PriorityQueue<long[]> heap = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        heap.offer(new long[]{0, 0, 0}); // cost, node, hasFlipped (0 or 1)

        Map<Long, Long> dist = new HashMap<>();
        dist.put(0L, 0L);

        long res = Long.MAX_VALUE;

        while (!heap.isEmpty()) {
            long[] current = heap.poll();
            long currentCost = current[0];
            int u = (int) current[1];
            int hasFlipped = (int) current[2];

            if (u == numNodes - 1) {
                res = Math.min(res, currentCost);
                continue;
