            if (currentCost > dist.getOrDefault(u * 2L + hasFlipped, Long.MAX_VALUE)) {
                continue;
            }

            // Traverse original edges
            for (long[] edge : graph.get(u)) {
                int v = (int) edge[0];
                long w = edge[1];
                long newCost = currentCost + w;
                long key = v * 2L + hasFlipped;
                if (newCost < dist.getOrDefault(key, Long.MAX_VALUE)) {
                    dist.put(key, newCost);
                    heap.offer(new long[]{newCost, v, hasFlipped});
                }
